sys_script.script:
(function executeRule(current, previous) {

    // On new record → set status as Pending
    if (current.operation() == 'insert') {
        current.u_request_status = 'pending';
        return;
    }

    var state = current.state.toString();

    // Sync request status with ticket state
    if (state == '2') { // In Progress

        current.u_request_status = 'in_progress';

    } else if (state == '3') { // On Hold / Awaiting Info

        current.u_request_status = 'awaiting_info';

    } else if (state == '6') { // Resolved

        var approval = current.u_approval_status.toString();

        if (approval == 'approved') {

            current.u_request_status = 'approved';

        } else if (approval == 'rejected') {

            current.u_request_status = 'rejected';

        }

    } else if (state == '7') { // Closed

        current.u_request_status = 'completed';

    }

})(current, previous);

(function executeRule(current, previous) {

    // Services that require admin approval
    var requiresApproval = [
        'Transcript',
        'Bonafide',
        'Fee Waiver',
        'Migration Certificate',
        'Degree Certificate'
    ];

    // Services that do not require approval
    var autoProcess = [
        'ID Card',
        'Library',
        'Bus Pass'
    ];

    var svcCategory = current.u_service_category.toString();

    // On ticket creation
    if (current.operation() == 'insert') {

        // Set initial approval status
        if (requiresApproval.indexOf(svcCategory) >= 0) {

            current.u_approval_status = 'pending_approval';

        } else {

            current.u_approval_status = 'not_required';

        }

        return;
    }

    // Sync approval status with ServiceNow approval state
    var approvalState = current.approval.toString();

    if (approvalState == 'approved') {

        current.u_approval_status = 'approved';
        current.u_request_status = 'approved';

    } else if (approvalState == 'rejected') {

        current.u_approval_status = 'rejected';
        current.u_request_status = 'rejected';

    }

})(current, previous);

(function executeRule(current, previous) {

    var serviceType = current.u_service_type.toString();

    var subCategoryMap = {
        'Transcript': 'Official,Unofficial',
        'ID Card': 'New,Replacement,Lost',
        'Fee Payment': 'Tuition,Fine,Hostel',
        'Bonafide': 'Study,Employment,Visa',
        'Library': 'New Membership,Renewal,No Dues',
        'Exam': 'Hall Ticket,Revaluation,Result'
    };

    if (subCategoryMap[serviceType]) {

        // Auto set first value if sub category is empty
        if (gs.nil(current.u_sub_category)) {
            current.u_sub_category = subCategoryMap[serviceType].split(',')[0];
        }

    } else {

        current.u_sub_category = '';

    }

})(current, previous);
